import 'package:permission_handler/permission_handler.dart'; class PermissionUtils { static Future<bool> camera() async => (await Permission.camera.request()).isGranted; static Future<bool> microphone() async => (await Permission.microphone.request()).isGranted; static Future<bool> location() async => (await Permission.location.request()).isGranted; static Future<bool> storage() async => (await Permission.storage.request()).isGranted; static Future<bool> notification() async => (await Permission.notification.request()).isGranted; static Future<bool> batteryOptimization() async => (await Permission.ignoreBatteryOptimizations.request()).isGranted; static Future<void> openSettings() => openAppSettings(); }